    """Simulate external payment gateway call"""
    apm_client.label(order_id=order_id, amount=amount, gateway='stripe')
    time.sleep(random.uniform(0.2, 0.5))
    
    # Simulate success/failure
    success = random.random() > 0.1
    return {'success': success, 'transaction_id': f'txn_{order_id}_{int(time.time())}'}


